COMPLETION_VERBS.push('numeric', 'num');
COMPLETION_SUBS.numeric = ['eval', 'calc', 'flag-namespace'];
COMPLETION_SUBS.num     = ['eval', 'calc', 'flag-namespace'];

// W761 — Model Poisoning Anomaly Detection. `kolm poison <bind|verify|
