// =============================================================================
// W783 - Cost attribution / chargeback dispatcher.
//
// Distinct-named (cmdW783Chargeback) so parallel W780/W781/W782 wave agents
// cannot collide on this symbol. Wired from main() via `case 'chargeback':`.
//
// Subcommands:
//   report  [--period YYYY-MM] [--group-by namespace|project|department]
//                                              GET  /v1/chargeback
//   export  --format csv|json [--period YYYY-MM] [--group-by D] [--out PATH]
//                                              POST /v1/chargeback/export
//   departments                                lists the canonical department
//                                              vocab used in dimension mapping
//
// All wrap the auth-gated routes so the CLI honors tenant fence + honest
// envelope contracts. version stamp matches /^w783-/.
// =============================================================================
async function cmdW783Chargeback(args) {
  const sub = (args && args[0]) || '';

  function _envApiKey() {
    return process.env.KOLM_API_KEY || process.env.KOLM_KEY || '';
  }
  function _envBase() {
    return (process.env.KOLM_BASE_URL || process.env.KOLM_URL || 'https://kolm.ai').replace(/\/$/, '');
  }
  function _flag(rest, name) {
    for (let i = 0; i < rest.length; i++) {
      if (rest[i] === '--' + name && i + 1 < rest.length) return rest[i + 1];
      if (typeof rest[i] === 'string' && rest[i].startsWith('--' + name + '=')) {
        return rest[i].slice(name.length + 3);
      }
    }
    return null;
  }
  function _print(envelope) {
    console.log(JSON.stringify(envelope, null, 2));
  }
  function _fail(envelope, code) {
    _print(envelope);
    process.exit(typeof code === 'number' ? code : EXIT.EXECUTION);
  }
  function _requireKey() {
    const key = _envApiKey();
    if (!key) {
      _fail({
        ok: false,
        error: 'auth_required',
        hint: 'set KOLM_API_KEY (kolm signup / kolm login)',
        version: 'w783-v1',
      }, EXIT.MISSING_PREREQ);
    }
    return key;
  }

  if (sub === '' || sub === 'help' || sub === '--help' || sub === '-h') {
    console.error('usage: kolm chargeback <report|export|departments|list-departments> [args]');
    console.error('  report  [--period YYYY-MM] [--group-by namespace|project|department]');
    console.error('  export  --format csv|json [--period YYYY-MM] [--group-by D] [--out PATH]');
    console.error('  departments                lists canonical department vocab');
    process.exit(EXIT.BAD_ARGS);
    return;
  }

  if (sub === 'report') {
    const rest = args.slice(1);
    const period = _flag(rest, 'period');
    const groupBy = _flag(rest, 'group-by') || _flag(rest, 'group_by') || 'namespace';
    const key = _requireKey();
    const qs = new URLSearchParams();
    if (period) qs.set('period', String(period));
    qs.set('group_by', String(groupBy));
    let resp;
    try {
      resp = await fetch(_envBase() + '/v1/chargeback?' + qs.toString(), {
        headers: { 'authorization': 'Bearer ' + key },
      });
    } catch (e) {
      _fail({ ok: false, error: 'network_error', detail: String(e && e.message || e), version: 'w783-v1' });
      return;
    }
    const body = await resp.json().catch(() => ({}));
    _print(body);
    if (!resp.ok) process.exit(EXIT.EXECUTION);
    return;
  }

  if (sub === 'export') {
    const rest = args.slice(1);
    const period = _flag(rest, 'period');
    const groupBy = _flag(rest, 'group-by') || _flag(rest, 'group_by') || 'namespace';
    const format = _flag(rest, 'format') || 'json';
    const out = _flag(rest, 'out');
    const key = _requireKey();
    const payload = { format, group_by: groupBy };
    if (period) payload.period = period;
    let resp;
    try {
      resp = await fetch(_envBase() + '/v1/chargeback/export', {
        method: 'POST',
        headers: { 'authorization': 'Bearer ' + key, 'content-type': 'application/json' },
        body: JSON.stringify(payload),
      });
    } catch (e) {
      _fail({ ok: false, error: 'network_error', detail: String(e && e.message || e), version: 'w783-v1' });
      return;
    }
    if (!resp.ok) {
      const body = await resp.json().catch(() => ({}));
      _print(body);
      process.exit(EXIT.EXECUTION);
      return;
    }
    const text = await resp.text();
    if (out) {
      try {
        const fs = await import('node:fs');
        fs.writeFileSync(out, text, 'utf8');
        console.error('# wrote ' + text.length + ' bytes to ' + out + ' (format=' + format + ')');
      } catch (e) {
        _fail({ ok: false, error: 'write_failed', detail: String(e && e.message || e), version: 'w783-v1' });
        return;
      }
    } else {
      process.stdout.write(text);
    }
    return;
  }

  if (sub === 'departments' || sub === 'list-departments') {
    // Pure local print of the canonical department vocab pulled from
    // src/chargeback.js. No network/auth needed.
    try {
      const mod = await import('../src/chargeback.js');
      const env = {
        ok: true,
        version: mod.CHARGEBACK_VERSION || 'w783-v1',
        group_by_dimensions: Array.from(mod.GROUP_BY_DIMENSIONS || []),
        departments: Array.from((mod.DEFAULTS && mod.DEFAULTS.DEPARTMENT_VOCAB) || []),
      };
      _print(env);
    } catch (e) {
      _fail({ ok: false, error: 'load_failed', detail: String(e && e.message || e), version: 'w783-v1' });
    }
    return;
  }

  console.error('usage: kolm chargeback <report|export|departments> [args]');
  process.exit(EXIT.BAD_ARGS);
}

// W783 - COMPLETION entries appended post-literal.
COMPLETION_VERBS.push('chargeback');
COMPLETION_SUBS.chargeback = ['report', 'export', 'departments', 'list-departments'];

// ─────────────────────────────────────────────────────────────────────────────
// W821 [T2] — `kolm pipeline {list,create,show,run,kscore,delete}` CLI.
//
// Append-only definition: the dispatch case lives near line 36951 and routes
// the W821 sub-verbs (and `run pl_*` IDs) to this function. We import the
// orchestrator dynamically so the CLI starts fast and so the sub-system
// stays optional in trimmed builds.
// ─────────────────────────────────────────────────────────────────────────────
function _w821FlagValue(args, ...names) {
  for (const n of names) {
    const i = args.indexOf(n);
    if (i >= 0 && i + 1 < args.length) return args[i + 1];
    const eqHit = args.find((a) => typeof a === 'string' && a.startsWith(n + '='));
    if (eqHit) return eqHit.slice(n.length + 1);
  }
  return undefined;
}

async function cmdW821Pipeline(rest) {
  const args = Array.isArray(rest) ? rest.slice() : [];
  const sub = args.shift();
  // No module-scope _fail/_print exist (each cmd function defines its own); inline the envelope-emit shape.
  const fail = (env) => { console.error(JSON.stringify(env)); process.exit(EXIT.SOFT_FAIL || 2); };
  const print = (env) => { console.log(JSON.stringify(env)); };
  let mod;
  try {
    mod = await import('../src/pipeline-orchestrator.js');
  } catch (e) {
    return fail({
      ok: false,
      error: 'pipeline_orchestrator_load_failed',
      detail: (e && e.message) || String(e),
      version: 'w821-v1',
    });
  }
  const V = mod.PIPELINE_ORCHESTRATOR_VERSION || 'w821-v1';

  if (sub === 'list') {
    try {
      const rows = mod.listPipelines({});
      return print({ ok: true, version: V, count: rows.length, pipelines: rows });
    } catch (e) {
      return fail({ ok: false, error: 'pipeline_list_failed', detail: (e && e.message) || String(e), version: V });
    }
  }

  if (sub === 'create') {
    const name = _w821FlagValue(args, '--name', '-n');
    const file = _w821FlagValue(args, '--file', '-f');
    if (!name || !file) {
      return fail({
        ok: false,
        error: 'usage',
        usage: 'kolm pipeline create --name <name> --file <kolm.pipeline.yaml>',
        version: V,
      });
    }
    try {
      const fs = await import('node:fs');
      const yaml = fs.readFileSync(file, 'utf8');
      const result = mod.createPipeline({ name, yaml });
      if (!result.ok) return fail({ ...result, version: V });
      return print({ ok: true, version: V, pipeline: result });
    } catch (e) {
      return fail({ ok: false, error: 'pipeline_create_failed', detail: (e && e.message) || String(e), version: V });
    }
  }

  if (sub === 'show') {
    const id = args[0];
    if (!id) return fail({ ok: false, error: 'usage', usage: 'kolm pipeline show <pl_id>', version: V });
    try {
      const row = mod.getPipeline(id, {});
      if (!row) return fail({ ok: false, error: 'pipeline_not_found', id, version: V });
      return print({ ok: true, version: V, pipeline: row });
    } catch (e) {
      return fail({ ok: false, error: 'pipeline_show_failed', detail: (e && e.message) || String(e), version: V });
    }
  }

  if (sub === 'delete') {
    const id = args[0];
    if (!id) return fail({ ok: false, error: 'usage', usage: 'kolm pipeline delete <pl_id>', version: V });
    try {
      const result = mod.deletePipeline(id, {});
      if (!result.ok) return fail({ ...result, version: V });
      return print({ ok: true, version: V, deleted_id: id });
    } catch (e) {
      return fail({ ok: false, error: 'pipeline_delete_failed', detail: (e && e.message) || String(e), version: V });
    }
  }

  if (sub === 'run') {
    const id = args[0];
    if (!id) return fail({ ok: false, error: 'usage', usage: 'kolm pipeline run <pl_id> [--input-json <json>]', version: V });
    let input;
    const inputJson = _w821FlagValue(args, '--input-json', '--input');
    if (inputJson != null) {
      try { input = JSON.parse(inputJson); } catch (e) {
        return fail({ ok: false, error: 'input_json_invalid', detail: (e && e.message) || String(e), version: V });
      }
    }
    try {
      const row = mod.getPipeline(id, {});
      if (!row) return fail({ ok: false, error: 'pipeline_not_found', id, version: V });
      if (row.parse_error) {
        return fail({ ok: false, error: 'pipeline_parse_error', detail: row.parse_error, version: V });
      }
      // Honest envelope: no runtime is wired into the CLI by default. The HTTP
      // route accepts an injected runtime via registerPipelineRoutes(deps), but
      // the CLI path has no real .kolm loader bolted on yet.
      const result = await mod.orchestrate({
        pipeline: row.parsed,
        input,
        runtime: {
          runArtifact: async (artifactPath) => ({
            ok: false,
            error: 'runtime_required',
            hint: 'CLI cannot execute .kolm artifacts; use the HTTP /v1/pipelines/:id/run route with a wired runtime',
            artifact_path: artifactPath,
          }),
        },
      });
      return print({ ok: !!result.ok, version: V, pipeline_id: id, result });
    } catch (e) {
      return fail({ ok: false, error: 'pipeline_run_failed', detail: (e && e.message) || String(e), version: V });
    }
  }

  if (sub === 'kscore') {
    const id = args[0];
    if (!id) return fail({ ok: false, error: 'usage', usage: 'kolm pipeline kscore <pl_id> [--eval-set <json>]', version: V });
    try {
      const row = mod.getPipeline(id, {});
      if (!row) return fail({ ok: false, error: 'pipeline_not_found', id, version: V });
      if (row.parse_error || !row.parsed) {
        return fail({ ok: false, error: 'pipeline_parse_error', detail: row.parse_error || 'parsed pipeline unavailable', version: V });
      }
      let eval_set = {};
      const raw = _w821FlagValue(args, '--eval-set');
      if (raw) {
        try { eval_set = JSON.parse(raw); } catch (e) {
          return fail({ ok: false, error: 'eval_set_invalid', detail: (e && e.message) || String(e), version: V });
        }
      }
      const result = mod.computePipelineKScore({
        pipeline: row.parsed,
        eval_set,
        route_frequencies: {},
      });
      return print({ ok: !!result.ok, version: V, pipeline_id: id, kscore: result });
    } catch (e) {
      return fail({ ok: false, error: 'pipeline_kscore_failed', detail: (e && e.message) || String(e), version: V });
    }
  }

  return fail({
    ok: false,
    error: 'usage',
    usage: 'kolm pipeline <list|create|show|delete|run|kscore> [args]',
    version: V,
  });
}

// W821 - COMPLETION entries (W384 — preserve tokenize/distill/compile/full).
if (!COMPLETION_VERBS.includes('pipeline')) COMPLETION_VERBS.push('pipeline');
COMPLETION_SUBS.pipeline = Array.from(new Set([
  ...(COMPLETION_SUBS.pipeline || []),
  'tokenize', 'distill', 'compile', 'full', 'run',
  'list', 'create', 'show', 'delete', 'kscore',
]));

// =============================================================================
// S-3 — `kolm hf modelcard <artifact-dir> [--dry-run] [--out <path>]`
//
// Generates a Hugging Face Hub-compatible README.md (YAML frontmatter + body)
// from a kolm distill-run artifact directory. The artifact dir must contain
// either passport.json or merged/passport.json (kolm.passport/1 shape).
// An optional benchmark-summary.json sibling is auto-detected.
//
// Flags:
//   --dry-run               print the generated markdown to stdout, do not write
//   --out <path>            write README to this absolute path instead of the
//                           default merged/qwen-merged/README.md
//   --target-repo <slug>    HF repo slug (e.g. kolm/trinity-500)
//   --license <id>          override license (default apache-2.0)
//   --base-model <id>       override base_model (default passport.student_base)
//   --benchmark <path>      explicit path to benchmark JSON
//
// Exit codes follow the rest of the CLI: 0 ok, 2 bad args, 3 missing artifacts.
// =============================================================================
async function cmdHfModelcard(args) {
  const sub = (args && args[0]) || '';
  const sr = args && args.length > 0 ? args.slice(1) : [];
  if (sub === '' || sub === 'help' || sub === '--help' || sub === '-h') {
    console.error('usage: kolm hf modelcard <artifact-dir> [--dry-run] [--out <path>]');
    console.error('       [--target-repo <kolm/name>] [--license <id>] [--base-model <id>]');
    console.error('       [--benchmark <path>] [--tag <t>]...');
    console.error('');
    console.error('generates a Hugging Face Hub-compatible README.md from a distill-run');
    console.error('artifact dir (must contain passport.json or merged/passport.json).');
    process.exit(2);
    return;
  }
  if (sub !== 'modelcard' && sub !== 'card') {
    console.error(`error: unknown hf sub-verb '${sub}'.`);
    console.error('try: kolm hf modelcard <artifact-dir>');
    process.exit(2);
    return;
  }
  // Parse subcommand args. First positional is the artifact dir.
  let artifactDir = null;
  let dryRun = false;
  let outPath = null;
  let targetRepo = null;
  let licenseOverride = null;
  let baseModelOverride = null;
  let benchmarkPath = null;
  const tagOverrides = [];
  for (let i = 0; i < sr.length; i++) {
    const a = sr[i];
    if (a === '--dry-run') { dryRun = true; continue; }
    if (a === '--out')          { outPath = sr[++i]; continue; }
    if (a === '--target-repo')  { targetRepo = sr[++i]; continue; }
    if (a === '--license')      { licenseOverride = sr[++i]; continue; }
    if (a === '--base-model')   { baseModelOverride = sr[++i]; continue; }
    if (a === '--benchmark')    { benchmarkPath = sr[++i]; continue; }
    if (a === '--tag')          { tagOverrides.push(sr[++i]); continue; }
    if (a.startsWith('-')) {
      console.error(`error: unknown flag '${a}'`);
      process.exit(2);
      return;
    }
    if (!artifactDir) { artifactDir = a; continue; }
  }
  if (!artifactDir) {
    console.error('error: artifact-dir is required.');
    console.error('usage: kolm hf modelcard <artifact-dir> [--dry-run]');
    process.exit(2);
    return;
  }
  // Resolve to absolute path so callers can pass a relative dir.
  const fs = await import('node:fs');
  const path = await import('node:path');
  const abs = path.isAbsolute(artifactDir) ? artifactDir : path.resolve(process.cwd(), artifactDir);
  if (!fs.existsSync(abs)) {
    console.error(`error: artifact dir does not exist: ${abs}`);
    process.exit(3);
    return;
  }
  const mod = await import('../src/hf-modelcard.js');
  if (dryRun) {
    // Read passport + benchmark inline, run generateModelCard, print.
    const passportCandidates = [
      path.join(abs, 'passport.json'),
      path.join(abs, 'merged', 'passport.json'),
    ];
    const passportPath = passportCandidates.find((p) => fs.existsSync(p));
    if (!passportPath) {
      console.error(`error: no passport.json found at any of: ${passportCandidates.join(' OR ')}`);
      process.exit(3);
      return;
    }
    const passport = JSON.parse(fs.readFileSync(passportPath, 'utf8'));
    let benchmark = null;
    const benchmarkCandidates = benchmarkPath ? [benchmarkPath] : [
      path.join(abs, 'benchmark-summary.json'),
      path.join(abs, 'merged', 'benchmark-summary.json'),
    ];
    for (const bp of benchmarkCandidates) {
      if (fs.existsSync(bp)) {
        try { benchmark = JSON.parse(fs.readFileSync(bp, 'utf8')); break; }
        catch { /* ignore parse error — fall through to no-benchmark */ }
      }
    }
    const gen = mod.generateModelCard({
      passport,
      benchmark,
      artifactDir: abs,
      target_repo: targetRepo,
      license: licenseOverride,
      base_model: baseModelOverride,
      tags: tagOverrides.length > 0 ? tagOverrides : undefined,
    });
    process.stdout.write(gen.readme);
    return;
  }
  // Write to disk via writeModelCard helper.
  try {
    const opts = {
      target_repo: targetRepo,
      license: licenseOverride,
      base_model: baseModelOverride,
      benchmarkPath,
    };
    if (tagOverrides.length > 0) opts.tags = tagOverrides;
    if (outPath) {
      opts.subdir = path.dirname(outPath);
      opts.outFile = path.basename(outPath);
    }
    const result = mod.writeModelCard({ artifactDir: abs, options: opts });
    console.log(JSON.stringify({
      ok: true,
      path: result.path,
      bytes: result.bytes,
      passport_path: result.passport_path,
      benchmark_path: result.benchmark_path,
      frontmatter_fields: Object.keys(result.frontmatter),
    }, null, 2));
  } catch (e) {
    console.error('error:', e && e.message ? e.message : String(e));
    process.exit(3);
  }
}

if (!COMPLETION_VERBS.includes('hf')) COMPLETION_VERBS.push('hf');
COMPLETION_SUBS.hf = Array.from(new Set([
  ...(COMPLETION_SUBS.hf || []),
  'modelcard', 'card',
]));

main();
